  // ── LESSONS: Aerodynamics educational content ──
  var LESSONS = {
    lift: { title: 'How Wings Create Lift', icon: '🛫', content: "Lift is generated by the shape of the wing (airfoil). Air moves faster over the curved top surface, creating lower pressure above the wing than below. This pressure difference pushes the wing UP. Lift increases with speed² — double your speed, quadruple your lift!", formula: 'L = ½ρv²SCₗ', variables: 'ρ=air density, v=velocity, S=wing area, Cₗ=lift coefficient' },
    drag: { title: 'Drag: The Force That Slows You', icon: '💨', content: "Drag opposes motion through the air. There are two types: parasite drag (from the shape of the aircraft pushing through air) increases with speed², and induced drag (a byproduct of creating lift) decreases with speed. Together they create a 'drag bucket' — an optimal speed where total drag is minimized.", formula: 'D = ½ρv²SCd', variables: 'ρ=air density, v=velocity, S=reference area, Cd=drag coefficient' },
    thrust: { title: 'Thrust: Pushing Forward', icon: '🔥', content: "Thrust is produced by engines — either propellers (which are spinning airfoils) or jet engines (which accelerate air backward, pushing the plane forward via Newton's Third Law). More thrust = more acceleration. In level flight, thrust exactly equals drag.", formula: 'F = ma (Newton\'s Second Law)', variables: 'When thrust > drag, the plane accelerates. When thrust < drag, it decelerates.' },
    weight: { title: 'Weight & the Balance of Forces', icon: '⚖️', content: "In straight, level, unaccelerated flight, four forces are in perfect balance: Lift = Weight, and Thrust = Drag. When you pitch up, you trade speed for altitude (kinetic energy → potential energy). When you pitch down, you trade altitude for speed. This is conservation of energy in action!", formula: 'W = mg', variables: 'In level flight: L=W and T=D. Climbing: L > W component. Descending: W component > L.' },
    bernoulli: { title: "Bernoulli's Principle", icon: '🌊', content: "Daniel Bernoulli discovered that as a fluid (including air) speeds up, its pressure drops. This is why airplane wings work: the curved upper surface makes air travel faster, reducing pressure on top. The higher pressure underneath pushes the wing up. You can demonstrate this by blowing over a piece of paper — it rises!", formula: 'P + ½ρv² + ρgh = constant', variables: 'P=static pressure, ρ=density, v=velocity, g=gravity, h=height — along a streamline' },
    navigation: { title: 'How Pilots Navigate', icon: '🧭', content: "Modern navigation uses GPS, but the fundamentals haven't changed: heading (compass direction), airspeed, altitude, and time. Great circle routes (the shortest path between two points on a sphere) appear curved on flat maps but are actually straight on a globe. That's why flights from the US to Europe often go over Greenland!", formula: 'd = 2R·arcsin(√(sin²(Δlat/2) + cos(lat1)·cos(lat2)·sin²(Δlon/2)))', variables: 'Haversine formula: calculates great-circle distance between two lat/lon points' },
  };

